// ═══════════════════════════════════════════════════
// Alert Detail Panel - Slide-in investigation panel
// ═══════════════════════════════════════════════════

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { api } from '@/api';
import type { AnomalyDetail } from '@/types';
import {
  X, ShieldAlert, MapPin, Server, Globe, Clock,
  AlertTriangle, Ban, Eye, Radio, Network,
  ArrowRight, Activity, Hash, Terminal, Bell,
  MessageSquare, Loader2, CheckCircle2, AlertOctagon
} from 'lucide-react';
import { useState } from 'react';

interface AlertDetailPanelProps {
  anomalyId: number;
  onClose: () => void;
}

export default function AlertDetailPanel({ anomalyId, onClose }: AlertDetailPanelProps) {
  const queryClient = useQueryClient();
  const [actionStatus, setActionStatus] = useState<{ action: string; status: 'idle' | 'loading' | 'success' | 'error' }>({ action: '', status: 'idle' });

  // Fetch anomaly detail
  const { data, isLoading, error } = useQuery<AnomalyDetail>({
    queryKey: ['anomalyDetail', anomalyId],
    queryFn: () => api.anomalyDetail(anomalyId),
  });

  // Mute mutation
  const muteMutation = useMutation({
    mutationFn: async (ip: string) => {
      const res = await fetch('/api/mutes', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ip, attack_type: 'ALL', duration_seconds: 3600 }),
      });
      if (!res.ok) throw new Error(`Mute failed: ${res.status}`);
      return res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['mutes'] });
      queryClient.invalidateQueries({ queryKey: ['anomalyDetail', anomalyId] });
      setActionStatus({ action: 'mute', status: 'success' });
      setTimeout(() => setActionStatus({ action: '', status: 'idle' }), 3000);
    },
    onError: (err) => {
      setActionStatus({ action: 'mute', status: 'error' });
      setTimeout(() => setActionStatus({ action: '', status: 'idle' }), 3000);
    },
  });

  // Block mutation (calls OPNsense block API)
  const blockMutation = useMutation({
    mutationFn: async (ip: string) => {
      const res = await fetch(`/api/opnsense/block?ip=${encodeURIComponent(ip)}`, {
        method: 'POST',
      });
      if (!res.ok) throw new Error(`Block failed: ${res.status}`);
      return res.json();
    },
    onSuccess: () => {
      setActionStatus({ action: 'block', status: 'success' });
      setTimeout(() => setActionStatus({ action: '', status: 'idle' }), 3000);
    },
    onError: () => {
      setActionStatus({ action: 'block', status: 'error' });
      setTimeout(() => setActionStatus({ action: '', status: 'idle' }), 3000);
    },
  });

  // Watchlist mutation
  const watchlistMutation = useMutation({
    mutationFn: async (ip: string) => {
      const res = await fetch(`/api/watchlist?ip=${encodeURIComponent(ip)}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
      });
      if (!res.ok) throw new Error(`Watchlist failed: ${res.status}`);
      return res.json();
    },
    onSuccess: () => {
      setActionStatus({ action: 'watchlist', status: 'success' });
      setTimeout(() => setActionStatus({ action: '', status: 'idle' }), 3000);
    },
    onError: () => {
      setActionStatus({ action: 'watchlist', status: 'error' });
      setTimeout(() => setActionStatus({ action: '', status: 'idle' }), 3000);
    },
  });

  const severityColor = (sev: string) => {
    switch (sev) {
      case 'CRITICAL': return 'text-cyber-red border-cyber-red bg-cyber-red/10';
      case 'HIGH': return 'text-cyber-orange border-cyber-orange bg-cyber-orange/10';
      case 'MEDIUM': return 'text-cyber-yellow border-cyber-yellow bg-cyber-yellow/10';
      default: return 'text-cyber-green border-cyber-green bg-cyber-green/10';
    }
  };

  const threatScoreColor = (score: number) => {
    if (score >= 80) return 'text-cyber-red';
    if (score >= 50) return 'text-cyber-orange';
    if (score >= 20) return 'text-cyber-yellow';
    return 'text-cyber-green';
  };

  if (isLoading) {
    return (
      <div className="fixed inset-0 z-50 flex justify-end" onClick={onClose}>
        <div className="min-h-screen w-full max-w-xl bg-cyber-panel border-l border-cyber-border/50 backdrop-blur-xl p-6 flex items-center justify-center" onClick={e => e.stopPropagation()}>
          <div className="flex flex-col items-center gap-4">
            <Loader2 size={32} className="text-cyber-cyan animate-spin" />
            <span className="text-cyber-textMuted font-mono text-sm">Loading alert details...</span>
          </div>
        </div>
      </div>
    );
  }

  if (error || !data) {
    return (
      <div className="fixed inset-0 z-50 flex justify-end" onClick={onClose}>
        <div className="min-h-screen w-full max-w-xl bg-cyber-panel border-l border-cyber-border/50 backdrop-blur-xl p-6 flex flex-col items-center justify-center gap-4" onClick={e => e.stopPropagation()}>
          <AlertOctagon size={32} className="text-cyber-red" />
          <span className="text-cyber-textMuted font-mono">Failed to load: {error?.message || 'Unknown error'}</span>
          <button onClick={onClose} className="text-cyber-cyan hover:underline font-mono text-sm">Close</button>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 z-50 flex justify-end" onClick={onClose}>
      {/* Backdrop */}
      <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" />

      {/* Panel */}
      <div className="relative min-h-screen w-full max-w-xl bg-cyber-panel/95 border-l border-cyber-border/50 backdrop-blur-xl overflow-y-auto scanlines" onClick={e => e.stopPropagation()}>
        {/* Header */}
        <div className="sticky top-0 z-10 flex items-center justify-between p-4 border-b border-cyber-border/30 bg-cyber-panel/90 backdrop-blur-md">
          <div className="flex items-center gap-3">
            <ShieldAlert size={20} className="text-cyber-red" />
            <h3 className="text-lg font-bold">Alert Investigation</h3>
            <span className={`cyber-badge ${severityColor(data.severity)}`}>{data.severity}</span>
            {data.is_muted && <span className="cyber-badge border-cyber-yellow text-cyber-yellow">Muted</span>}
          </div>
          <button
            onClick={onClose}
            className="p-2 rounded-md hover:bg-cyber-panel/50 text-cyber-textMuted hover:text-cyber-text transition-colors"
          >
            <X size={18} />
          </button>
        </div>

        {/* Content */}
        <div className="p-4 space-y-4">
          {/* ── Core Info ── */}
          <div className="cyber-card p-4">
            <h4 className="text-sm font-bold text-cyber-cyan mb-3 flex items-center gap-2">
              <Terminal size={14} /> Alert Details
            </h4>
            <div className="space-y-2 text-sm font-mono">
              <InfoRow icon={<Hash size={12} />} label="ID" value={`#${data.id}`} />
              <InfoRow icon={<ShieldAlert size={12} />} label="Type" value={data.type} />
              <InfoRow icon={<Clock size={12} />} label="Timestamp" value={data.timestamp} />
              <InfoRow icon={<Activity size={12} />} label="Protocol" value={data.protocol || 'N/A'} />
              {data.destination_port && (
                <InfoRow icon={<Network size={12} />} label="Dest Port" value={String(data.destination_port)} />
              )}
              {data.description && (
                <div className="pt-2 border-t border-cyber-border/20">
                  <span className="text-cyber-textMuted">Description: </span>
                  <span className="text-cyber-text">{data.description}</span>
                </div>
              )}
            </div>
          </div>

          {/* ── Source / Destination ── */}
          <div className="cyber-card p-4">
            <h4 className="text-sm font-bold text-cyber-cyan mb-3 flex items-center gap-2">
              <ArrowRight size={14} /> Network Path
            </h4>
            <div className="flex items-center gap-3">
              <div className="flex-1 bg-cyber-panel/60 rounded-lg p-3 border border-cyber-border/30">
                <div className="text-xs text-cyber-textMuted mb-1">SOURCE</div>
                <div className="font-mono font-bold text-cyber-red">{data.source_ip || 'N/A'}</div>
              </div>
              <ArrowRight size={20} className="text-cyber-cyan flex-shrink-0" />
              <div className="flex-1 bg-cyber-panel/60 rounded-lg p-3 border border-cyber-border/30">
                <div className="text-xs text-cyber-textMuted mb-1">DESTINATION</div>
                <div className="font-mono font-bold text-cyber-green">{data.destination_ip || 'N/A'}</div>
                {data.destination_port && (
                  <div className="font-mono text-xs text-cyber-textMuted mt-1">:{data.destination_port}</div>
                )}
              </div>
            </div>
          </div>

          {/* ── Source Event ── */}
          {data.event && (
            <div className="cyber-card p-4">
              <h4 className="text-sm font-bold text-cyber-cyan mb-3 flex items-center gap-2">
                <Terminal size={14} /> Source Event
              </h4>
              <div className="space-y-1.5 text-sm font-mono">
                <InfoRow icon={<Clock size={12} />} label="Time" value={data.event.timestamp || 'N/A'} />
                <InfoRow icon={<ShieldAlert size={12} />} label="Rule" value={data.event.rule_name || 'N/A'} />
                <InfoRow icon={<Server size={12} />} label="Interface" value={data.event.interface || 'N/A'} />
                <InfoRow icon={<ArrowRight size={12} />} label="Action" value={data.event.action || 'N/A'} />
                <InfoRow icon={<Globe size={12} />} label="Direction" value={data.event.direction || 'N/A'} />
                {data.event.log_type && (
                  <InfoRow icon={<Activity size={12} />} label="Log Type" value={data.event.log_type} />
                )}
              </div>
            </div>
          )}

          {/* ── IP Threat Profile ── */}
          {data.ip_profile && (
            <div className="cyber-card p-4">
              <h4 className="text-sm font-bold text-cyber-cyan mb-3 flex items-center gap-2">
                <Globe size={14} /> IP Threat Profile
              </h4>
              <div className="space-y-2 text-sm font-mono">
                <div className="flex items-center justify-between">
                  <span className="text-cyber-textMuted">Threat Score</span>
                  <span className={`font-bold ${threatScoreColor(data.ip_profile.unified_score || 0)}`}>
                    {Math.round(data.ip_profile.unified_score || 0)}/100
                  </span>
                </div>
                {/* Score bar */}
                <div className="w-full h-2 bg-cyber-panel/60 rounded-full overflow-hidden">
                  <div
                    className={`h-full rounded-full transition-all ${
                      (data.ip_profile.unified_score || 0) >= 80 ? 'bg-cyber-red' :
                      (data.ip_profile.unified_score || 0) >= 50 ? 'bg-cyber-orange' :
                      (data.ip_profile.unified_score || 0) >= 20 ? 'bg-cyber-yellow' :
                      'bg-cyber-green'
                    }`}
                    style={{ width: `${Math.min(data.ip_profile.unified_score || 0, 100)}%` }}
                  />
                </div>
                <InfoRow icon={<Activity size={12} />} label="Total Events" value={String(data.ip_profile.total_events || 0)} />
                <InfoRow icon={<Server size={12} />} label="FW Events" value={String(data.ip_profile.firewall_events || 0)} />
                {data.ip_profile.ids_events && data.ip_profile.ids_events > 0 && (
                  <InfoRow icon={<ShieldAlert size={12} />} label="IDS Events" value={String(data.ip_profile.ids_events)} />
                )}
                {data.ip_profile.http_events && data.ip_profile.http_events > 0 && (
                  <InfoRow icon={<Globe size={12} />} label="HTTP Events" value={String(data.ip_profile.http_events)} />
                )}
                {data.ip_profile.geo_info?.country_name && (
                  <InfoRow icon={<MapPin size={12} />} label="Geo" value={`${data.ip_profile.geo_info.country_name}${data.ip_profile.geo_info.city ? `, ${data.ip_profile.geo_info.city}` : ''}`} />
                )}
                <InfoRow icon={<Clock size={12} />} label="First Seen" value={data.ip_profile.first_seen || 'N/A'} />
                <InfoRow icon={<Clock size={12} />} label="Last Seen" value={data.ip_profile.last_seen || 'N/A'} />
              </div>
            </div>
          )}

          {/* ── Related Alerts ── */}
          {data.related_alerts.length > 0 && (
            <div className="cyber-card p-4">
              <h4 className="text-sm font-bold text-cyber-cyan mb-3 flex items-center gap-2">
                <Radio size={14} /> Related Alerts ({data.related_alerts.length})
              </h4>
              <div className="space-y-1.5">
                {data.related_alerts.map((rel, i) => (
                  <div key={i} className="flex items-center gap-2 text-xs font-mono p-2 rounded bg-cyber-panel/40 border border-cyber-border/20">
                    <span className={`px-1.5 py-0.5 rounded ${severityColor(rel.severity)} text-xs`}>{rel.severity}</span>
                    <span className="text-cyber-text truncate">{rel.type}</span>
                    <span className="text-cyber-textMuted ml-auto flex-shrink-0">{rel.timestamp}</span>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* ── Status ── */}
          <div className="cyber-card p-4">
            <h4 className="text-sm font-bold text-cyber-cyan mb-3 flex items-center gap-2">
              <Bell size={14} /> Notification Status
            </h4>
            <div className="flex gap-4 text-sm font-mono">
              <div className="flex items-center gap-2">
                {data.alert_sent ? <CheckCircle2 size={14} className="text-cyber-green" /> : <AlertTriangle size={14} className="text-cyber-textMuted" />}
                <span className="text-cyber-textMuted">Alert</span>
                <span className={data.alert_sent ? 'text-cyber-green' : 'text-cyber-textMuted'}>
                  {data.alert_sent ? 'Sent' : 'Not sent'}
                </span>
              </div>
              <div className="flex items-center gap-2">
                {data.discord_sent ? <MessageSquare size={14} className="text-cyber-green" /> : <AlertTriangle size={14} className="text-cyber-textMuted" />}
                <span className="text-cyber-textMuted">Discord</span>
                <span className={data.discord_sent ? 'text-cyber-green' : 'text-cyber-textMuted'}>
                  {data.discord_sent ? 'Sent' : 'Not sent'}
                </span>
              </div>
            </div>
          </div>

          {/* ── Action Buttons ── */}
          <div className="cyber-card p-4">
            <h4 className="text-sm font-bold text-cyber-cyan mb-3 flex items-center gap-2">
              <Ban size={14} /> Actions
            </h4>
            <div className="flex flex-wrap gap-2">
              {/* Mute IP */}
              <ActionButton
                icon={<Eye size={14} />}
                label={data.is_muted ? 'Muted' : 'Mute IP'}
                severity="warning"
                isLoading={muteMutation.isPending}
                isSuccess={actionStatus.action === 'mute' && actionStatus.status === 'success'}
                isError={actionStatus.action === 'mute' && actionStatus.status === 'error'}
                disabled={data.is_muted}
                onClick={() => {
                  if (data.source_ip) {
                    muteMutation.mutate(data.source_ip);
                  }
                }}
              />

              {/* Block in OPNsense */}
              <ActionButton
                icon={<Ban size={14} />}
                label="Block IP"
                severity="danger"
                isLoading={blockMutation.isPending}
                isSuccess={actionStatus.action === 'block' && actionStatus.status === 'success'}
                isError={actionStatus.action === 'block' && actionStatus.status === 'error'}
                onClick={() => {
                  if (data.source_ip) {
                    blockMutation.mutate(data.source_ip);
                  }
                }}
              />

              {/* Add to watchlist */}
              <ActionButton
                icon={<Radio size={14} />}
                label="Watchlist"
                severity="info"
                isLoading={watchlistMutation.isPending}
                isSuccess={actionStatus.action === 'watchlist' && actionStatus.status === 'success'}
                isError={actionStatus.action === 'watchlist' && actionStatus.status === 'error'}
                onClick={() => {
                  if (data.source_ip) {
                    watchlistMutation.mutate(data.source_ip);
                  }
                }}
              />
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

// ── Sub-components ──

function InfoRow({ icon, label, value }: { icon: any; label: string; value: string }) {
  return (
    <div className="flex items-center gap-2">
      <span className="text-cyber-textMuted flex-shrink-0">{icon}</span>
      <span className="text-cyber-textMuted w-24 flex-shrink-0">{label}</span>
      <span className="text-cyber-text break-all">{value}</span>
    </div>
  );
}

function ActionButton({
  icon,
  label,
  severity,
  isLoading,
  isSuccess,
  isError,
  disabled,
  onClick,
}: {
  icon: JSX.Element;
  label: string;
  severity: 'danger' | 'warning' | 'info';
  isLoading: boolean;
  isSuccess: boolean;
  isError: boolean;
  disabled?: boolean;
  onClick: () => void;
}) {
  const baseColor = severity === 'danger' ? 'cyber-red' : severity === 'warning' ? 'cyber-yellow' : 'cyber-cyan';
  const colorClass = `border-cyber-${baseColor}/30 text-cyber-${baseColor} hover:bg-cyber-${baseColor}/10`;

  if (isSuccess) {
    return (
      <button disabled className="flex items-center gap-2 px-3 py-2 rounded-md border border-cyber-green/30 text-cyber-green bg-cyber-green/5 cursor-default font-mono text-sm">
        <CheckCircle2 size={14} />
        {label}: Done
      </button>
    );
  }

  if (isError) {
    return (
      <button onClick={onClick} className="flex items-center gap-2 px-3 py-2 rounded-md border border-cyber-red/30 text-cyber-red bg-cyber-red/5 hover:bg-cyber-red/10 font-mono text-sm">
        <AlertOctagon size={14} />
        {label}: Retry
      </button>
    );
  }

  return (
    <button
      onClick={onClick}
      disabled={disabled || isLoading}
      className={`flex items-center gap-2 px-3 py-2 rounded-md border ${colorClass} font-mono text-sm transition-all disabled:opacity-40 disabled:cursor-not-allowed`}
    >
      {isLoading ? <Loader2 size={14} className="animate-spin" /> : icon}
      {label}
    </button>
  );
}